function candidate(start, target) {
  let base = start === "" ? "." : start;

  if (base.length > 0 && base.endsWith("/")) {
    base = base.slice(0, -1);
  }

  let prefix = "";

  while (true) {
    if (target === base) {
      return prefix || ".";
    }

    if (target.startsWith(base + "/")) {
      return prefix + target.slice(base.length + 1);
    }

    const slash = base.lastIndexOf("/");

    if (slash <= 0 || base.slice(0, slash).endsWith(":/")) {
      return target;
    }

    base = base.slice(0, slash);
    prefix += "../";
  }
}
